1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	type Step = QuoteStep | ClaimStep;
25	
26	interface Customer {
27	  yearsWithMHPCO: number;
28	}
29	
30	interface Scenario {
31	  customer: Customer;
32	  steps: Step[];
33	}
34	
35	type QuoteResult = { premium: number };
36	type ClaimResult = { payout: number; remainingCap: number };
37	type StepResult = QuoteResult | ClaimResult;
38	
39	const BASE_PREMIUM: Record<string, number> = {
40	  sword: 100,
41	  amulet: 60,
42	  staff: 80,
43	  potion: 40,
44	  rune: 25,
45	  moonstone: 25,
46	};
47	
48	const INSURANCE_VALUE: Record<string, number> = {
49	  sword: 1000,
50	  amulet: 600,
51	  staff: 800,
52	  potion: 400,
53	  rune: 250,
54	  moonstone: 250,
55	};
56	
57	const FIRST_INSURANCE_RATE = 0.1;
58	const PROCESSING_FEE = 5;
59	const LOYALTY_THRESHOLD_YEARS = 2;
60	const LOYALTY_DISCOUNT_RATE = 0.2;
61	const FOLLOWUP_DISCOUNT_RATE = 0.15;
62	const DEDUCTIBLE = 100;
63	const HIGH_DAMAGE_ENCHANTMENT_THRESHOLD = 8;
64	const HALF_REIMBURSEMENT_RATE = 0.5;
65	const CAP_MULTIPLIER = 2;
66	
67	const COMPONENT_TYPES = ["rune", "moonstone"];
68	const COMPONENT_BLOCK_SIZE = 3;
69	const COMPONENT_BLOCK_PREMIUM = 60;
70	
71	const isComponent = (type: string): boolean => COMPONENT_TYPES.includes(type);
72	
73	const typeBasePremium = (type: string, count: number): number =>
74	  isComponent(type) && count === COMPONENT_BLOCK_SIZE
75	    ? COMPONENT_BLOCK_PREMIUM
76	    : count * BASE_PREMIUM[type];
77	
78	const CURSE_RATE = 0.5;
79	const HIGH_ENCHANTMENT_THRESHOLD = 5;
80	const HIGH_ENCHANTMENT_RATE = 0.3;
81	
82	const surchargeForItem = (item: Item): number => {
83	  const base = BASE_PREMIUM[item.type];
84	  const curse = item.cursed ? CURSE_RATE * base : 0;
85	  const highEnchantment =
86	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
87	      ? HIGH_ENCHANTMENT_RATE * base
88	      : 0;
89	  return curse + highEnchantment;
90	};
91	
92	const itemSurcharges = (items: Item[]): number =>
93	  items.reduce((sum, item) => sum + surchargeForItem(item), 0);
94	
95	const countByType = (items: Item[]): Map<string, number> => {
96	  const counts = new Map<string, number>();
97	  for (const item of items) {
98	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
99	  }
100	  return counts;
101	};
102	
103	const policyBasePremium = (items: Item[]): number =>
104	  [...countByType(items)].reduce(
105	    (total, [type, count]) => total + typeBasePremium(type, count),
106	    0,
107	  );
108	
109	const isLoyal = (customer: Customer): boolean =>
110	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
111	
112	const policyModifierRate = (customer: Customer, isFollowup: boolean): number =>
113	  FIRST_INSURANCE_RATE -
114	  (isLoyal(customer) ? LOYALTY_DISCOUNT_RATE : 0) -
115	  (isFollowup ? FOLLOWUP_DISCOUNT_RATE : 0);
116	
117	const quotePremium = (
118	  step: QuoteStep,
119	  customer: Customer,
120	  isFollowup: boolean,
121	): number => {
122	  const policyBase = policyBasePremium(step.items);
123	  const policyModifierAmount =
124	    policyBase * policyModifierRate(customer, isFollowup);
125	  return Math.ceil(
126	    policyBase +
127	      itemSurcharges(step.items) +
128	      policyModifierAmount +
129	      PROCESSING_FEE,
130	  );
131	};
132	
133	const insuranceSum = (items: Item[]): number =>
134	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
135	
136	const qualifiesForHalfReimbursement = (item: Item | undefined): boolean =>
137	  (item?.enchantment ?? 0) >= HIGH_DAMAGE_ENCHANTMENT_THRESHOLD;
138	
139	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
140	  qualifiesForHalfReimbursement(item)
141	    ? HALF_REIMBURSEMENT_RATE * damage.amount
142	    : damage.amount;
143	
144	const damagePayout = (damage: Damage, policyItems: Item[]): number => {
145	  const item = policyItems.find((it) => it.type === damage.itemType);
146	  return reimbursableAmount(damage, item) - DEDUCTIBLE;
147	};
148	
149	const damageCountByType = (damages: Damage[]): Map<string, number> => {
150	  const counts = new Map<string, number>();
151	  for (const damage of damages) {
152	    counts.set(damage.itemType, (counts.get(damage.itemType) ?? 0) + 1);
153	  }
154	  return counts;
155	};
156	
157	const validateDamages = (damages: Damage[], policyItems: Item[]): void => {
158	  const insuredCounts = countByType(policyItems);
159	  for (const [itemType, count] of damageCountByType(damages)) {
160	    if (count > (insuredCounts.get(itemType) ?? 0)) {
161	      throw new Error(
162	        `Claim rejected: ${count} ${itemType} damages exceed insured count`,
163	      );
164	    }
165	  }
166	};
167	
168	const claimResult = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
169	  validateDamages(step.incident.damages, policyItems);
170	  const cap = CAP_MULTIPLIER * insuranceSum(policyItems);
171	  const payout = step.incident.damages.reduce(
172	    (sum, damage) => sum + damagePayout(damage, policyItems),
173	    0,
174	  );
175	  return { payout: Math.floor(payout), remainingCap: cap - payout };
176	};
177	
178	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
179	  const policyItemsByStep = new Map<number, Item[]>();
180	  let quoteCount = 0;
181	  const results: StepResult[] = [];
182	  scenario.steps.forEach((step, index) => {
183	    if (step.op === "quote") {
184	      const isFollowup = quoteCount > 0;
185	      results.push({ premium: quotePremium(step, scenario.customer, isFollowup) });
186	      policyItemsByStep.set(index, step.items);
187	      quoteCount += 1;
188	    } else {
189	      const policyItems = policyItemsByStep.get(step.policy) ?? [];
190	      results.push(claimResult(step, policyItems));
191	    }
192	  });
193	  return { results };
194	};
